using System.Numerics;
using UniswapSharp.Core;
using UniswapSharp.Core.Entities;
using UniswapSharp.Core.Entities.Fractions;
using UniswapSharp.V3;
using UniswapSharp.V3.Entities;
using UniswapSharp.V3.Utils;
using static UniswapSharp.V3.Constants;

namespace UniswapSharp.Testing.V3;

// Ported from sdks/v3-sdk/src/swapRouter.test.ts (single trade input block).
public class SwapRouterTests
{
    private static readonly Ether ETHER = Ether.OnChain(1);
    private static readonly Token token0 = new(1, "0x0000000000000000000000000000000000000001", 18, "t0", "token0");
    private static readonly Token token1 = new(1, "0x0000000000000000000000000000000000000002", 18, "t1", "token1");
    private static readonly Token WETH = Weth9.Tokens[1];
    private const FeeAmount feeAmount = FeeAmount.MEDIUM;
    private static readonly BigInteger sqrtRatioX96 = EncodeSqrtRatioX96.Encode(1, 1);
    private const int liquidity = 1_000_000;

    private static Pool MakePool(Token a, Token b) => new(
        a, b, feeAmount, sqrtRatioX96, liquidity, TickMath.GetTickAtSqrtRatio(sqrtRatioX96),
        new List<Tick>
        {
            new(NearestUsableTick.Find(TickMath.MIN_TICK, TICK_SPACINGS[feeAmount]), liquidity, liquidity),
            new(NearestUsableTick.Find(TickMath.MAX_TICK, TICK_SPACINGS[feeAmount]), -liquidity, liquidity),
        });

    private static readonly Pool pool_0_1 = MakePool(token0, token1);
    private static readonly Pool pool_1_weth = MakePool(token1, WETH);

    private static readonly Percent slippageTolerance = new(1, 100);
    private const string recipient = "0x0000000000000000000000000000000000000003";
    private static readonly BigInteger deadline = 123;

    [Fact]
    public async Task SingleHopExactInput()
    {
        var trade = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1], token0, token1), CurrencyAmount<Token>.FromRawAmount(token0, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task SingleHopExactOutput()
    {
        var trade = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1], token0, token1), CurrencyAmount<Token>.FromRawAmount(token1, 100), TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task MultiHopExactInput()
    {
        var trade = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1, pool_1_weth], token0, WETH), CurrencyAmount<Token>.FromRawAmount(token0, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task MultiHopExactOutput()
    {
        var trade = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1, pool_1_weth], token0, WETH), CurrencyAmount<Token>.FromRawAmount(WETH, 100), TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task EthInExactInput()
    {
        var trade = await Trade<BaseCurrency, Token>.FromRoute(new Route<BaseCurrency, Token>([pool_1_weth], ETHER, token1), CurrencyAmount<BaseCurrency>.FromRawAmount(Ether.OnChain(1), 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x64", r.Value);
    }

    [Fact]
    public async Task EthInExactOutput()
    {
        var trade = await Trade<BaseCurrency, Token>.FromRoute(new Route<BaseCurrency, Token>([pool_1_weth], ETHER, token1), CurrencyAmount<Token>.FromRawAmount(token1, 100), TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x67", r.Value);
    }

    [Fact]
    public async Task EthOutExactInput()
    {
        var trade = await Trade<Token, BaseCurrency>.FromRoute(new Route<Token, BaseCurrency>([pool_1_weth], token1, ETHER), CurrencyAmount<Token>.FromRawAmount(token1, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task EthOutExactOutput()
    {
        var trade = await Trade<Token, BaseCurrency>.FromRoute(new Route<Token, BaseCurrency>([pool_1_weth], token1, ETHER), CurrencyAmount<BaseCurrency>.FromRawAmount(Ether.OnChain(1), 100), TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task SqrtPriceLimit()
    {
        var trade = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1], token0, token1), CurrencyAmount<Token>.FromRawAmount(token0, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline, SqrtPriceLimitX96 = BigInteger.Pow(2, 128) });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task FeeWithEthOut()
    {
        var trade = await Trade<Token, BaseCurrency>.FromRoute(new Route<Token, BaseCurrency>([pool_1_weth], token1, ETHER), CurrencyAmount<Token>.FromRawAmount(token1, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline, Fee = new Payments.FeeOptions { Fee = new Percent(5, 1000), Recipient = recipient } });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task FeeWithEthInExactOutput()
    {
        var trade = await Trade<BaseCurrency, Token>.FromRoute(new Route<BaseCurrency, Token>([pool_1_weth], ETHER, token1), CurrencyAmount<Token>.FromRawAmount(token1, 10), TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline, Fee = new Payments.FeeOptions { Fee = new Percent(5, 1000), Recipient = recipient } });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x0c", r.Value);
    }

    [Fact]
    public async Task Fee()
    {
        var trade = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1], token0, token1), CurrencyAmount<Token>.FromRawAmount(token0, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trade, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline, Fee = new Payments.FeeOptions { Fee = new Percent(5, 1000), Recipient = recipient } });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }
}
